def token_case(s):
    tokens = s.split('_')
    exception_list = ['URL', 'ID']

    # Edge case handling: if the input is already in camelCase or has no underscores, return it as is.
    if any(char.isupper() and not char.isalpha() for char in s) or '_' not in s:
        return s

    result_tokens = []
    for i, token in enumerate(tokens):
        if token in exception_list:
            result_tokens.append(token)
        elif i == 0:
            result_tokens.append(token.lower())
        else:
            result_tokens.append(token.capitalize())

    return ''.join(result_tokens)
